// ---------------------------------------------------------------------------
// PATCH /bot/settings
// ---------------------------------------------------------------------------
export const updateBotSettings = (
  botSettingsInput: BodyType<BotSettingsInput>,
  options?: SecondParameter<typeof customFetch>
) => {
  return customFetch<BotSettings>(
    {
      url: `/bot/settings`,
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      data: botSettingsInput,
    },
    options
  );
};

export const useUpdateBotSettings = <
  TError = ErrorType<ErrorResponse>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof updateBotSettings>>,
    TError,
    { data: BodyType<BotSettingsInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof updateBotSettings>>,
  TError,
  { data: BodyType<BotSettingsInput> },
  TContext
> => {
  const { mutation: mutationOptions, request: requestOptions } = options ?? {};

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof updateBotSettings>>,
    { data: BodyType<BotSettingsInput> }
  > = (props) => {
    const { data } = props ?? {};
    return updateBotSettings(data, requestOptions);
  };

  return useMutation({ mutationFn, ...mutationOptions });
};
